sql:
SELECT COUNT(DISTINCT loss_id) AS unique_losses_2022
FROM capital_losses
WHERE year = 2022;

SELECT COUNT(*) AS total_losses
FROM capital_losses
WHERE loss_amount > 0;

SELECT gain_amount, description
FROM capital_gains
WHERE gain_amount > 2000;

SELECT degree_type, COUNT(*) AS degree_count
FROM educations
GROUP BY degree_type;

SELECT income_range
FROM income_categories
WHERE upper_bound = (SELECT MAX(upper_bound) FROM income_categories);

SELECT loss_amount
FROM capital_losses
WHERE loss_amount = 0;

